  {
    "class": "chisel3.experimental.Trace$TraceNameAnnotation",
    "target": "~Foo|Foo",
    "chiselTarget": "~Foo|Foo"
  },
  {
    "class": "chisel3.experimental.Trace$TraceNameAnnotation",
    "target": "~Foo|Foo>a_0_a",
    "chiselTarget": "~Foo|Foo>a"
  },
  {
    "class": "chisel3.experimental.Trace$TraceNameAnnotation",
    "target": "~Foo|Foo>a_0_a",
    "chiselTarget": "~Foo|Foo>a[0]"
  },
  {
    "class": "chisel3.experimental.Trace$TraceNameAnnotation",
    "target": "~Foo|Foo>a_0_a",
    "chiselTarget": "~Foo|Foo>a[0].a"
  },
  {
    "class": "chisel3.experimental.Trace$TraceNameAnnotation",
    "target": "~Foo|Foo>a_0_b",
    "chiselTarget": "~Foo|Foo>a"
  },
